import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.DtwafDNl.js";const b=JSON.parse('{"title":"Backup & Restore","description":"","frontmatter":{},"headers":[],"relativePath":"features/backup.md","filePath":"features/backup.md"}'),i={name:"features/backup.md"};function s(n,e,l,c,p,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h1><p>Backup &amp; Restore gives admins a controlled way to protect the system configuration and call data. A manual backup can be created when needed, and each backup can include the database and call recordings so the important operational state is captured together.</p><p>Scheduled backups help reduce the risk of data loss by running automatically at a configurable interval. Retention settings keep storage under control by removing older backups after the chosen limit.</p><p>Restore operations support uploaded backup archives and let admins choose whether to restore the database, recordings, or both. During long-running backup and restore work, the UI shows live progress so operators know what stage the operation is in.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Manual backup creation from the admin UI</li><li>Database backup support</li><li>Call recording backup support</li><li>Scheduled backups with configurable interval</li><li>Retention policy for older backups</li><li>Restore from an uploaded backup archive</li><li>Independent database restore toggle</li><li>Independent recordings restore toggle</li><li>Live progress feed during backup and restore operations</li></ul>',6)])])}const h=a(i,[["render",s]]);export{b as __pageData,h as default};
